import{c as a,Q as t,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"Last Week in AI — 2026-05-08","description":"","frontmatter":{"title":"Last Week in AI — 2026-05-08","date":"2026-05-08T00:00:00.000Z","source":"Last Week in AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-08-last-week-in-ai.md","filePath":"research/ai-news/2026-05/2026-05-08-last-week-in-ai.md","lastUpdated":1779894392000}'),i={name:"research/ai-news/2026-05/2026-05-08-last-week-in-ai.md"};function o(s,e,l,c,p,h){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="📅-last-week-in-ai-—-2026-05-08" tabindex="-1">📅 Last Week in AI — 2026-05-08 <a class="header-anchor" href="#📅-last-week-in-ai-—-2026-05-08" aria-label="Permalink to &quot;📅 Last Week in AI — 2026-05-08&quot;">​</a></h1><blockquote><p>每週 AI 新聞摘要 + 編輯評論，含 Podcast 來源：<a href="https://lastweekin.ai/feed" target="_blank" rel="noreferrer">Last Week in AI</a></p></blockquote><hr><h2 id="last-week-in-ai-340-openai-vs-musk-microsoft-deepseek-v4-vision-banana" tabindex="-1"><a href="https://lastweekin.ai/p/last-week-in-ai-340-openai-vs-musk" target="_blank" rel="noreferrer">Last Week in AI #340 - OpenAI vs Musk + Microsoft, DeepSeek v4, Vision Banana</a> <a class="header-anchor" href="#last-week-in-ai-340-openai-vs-musk-microsoft-deepseek-v4-vision-banana" aria-label="Permalink to &quot;[Last Week in AI #340 - OpenAI vs Musk + Microsoft, DeepSeek v4, Vision Banana](https://lastweekin.ai/p/last-week-in-ai-340-openai-vs-musk)&quot;">​</a></h2><p><em>📅 Last Week in AI | 2026-05-05</em></p><h4 id="musk-testimony-dominated-first-week-of-musk-v-altman-you-can-t-just-steal-a-charity" tabindex="-1"><a href="https://www.cnbc.com/2026/05/02/musk-testimony-dominated-first-week-musk-v-altman-trial-in-oakland.html" target="_blank" rel="noreferrer">Musk testimony dominated first week of Musk v. Altman. &#39;You can&#39;t just steal a charity&#39;</a> <a class="header-anchor" href="#musk-testimony-dominated-first-week-of-musk-v-altman-you-can-t-just-steal-a-charity" aria-label="Permalink to &quot;[Musk testimony dominated first week of Musk v. Altman. &#39;You can&#39;t just steal a charity&#39;](https://www.cnbc.com/2026/05/02/musk-testimony-dominated-first-week-musk-v-altman-trial-in-oakland.html)&quot;">​</a></h4><p>Related:</p><ul><li><p><a href="https://www.theverge.com/ai-artificial-intelligence/920775/evidence-exhibits-elon-musk-sam-altman-openai-trial" target="_blank" rel="noreferrer">All the evidence revealed so far in Musk v. Altman</a></p></li><li><p><a href="https://www.cnbc.com/2026/05/04/musk-altman-open-ai-settlement-trial-brockman.html" target="_blank" rel="noreferrer">Musk texted OpenAI&#39;s Brockman about settlement two days before trial began</a></p></li><li><p><a href="https://www.businessinsider.com/musk-v-altman-trial-livestream-youtube-where-to-watch-2026-5" target="_blank" rel="noreferrer">The Elon Musk v. Sam Altman trial is now on YouTube</a></p></li><li><p><a href="https://www.wired.com/story/elon-musk-distill-openai-models-partly-xai/" target="_blank" rel="noreferrer">Elon Musk Seemingly Admits xAI Has Used OpenAI&#39;s Models to Train Its Own</a></p></li><li><p><a href="https://www.nytimes.com/2026/05/04/technology/elon-musk-greg-brockman-openai-trial.html" target="_blank" rel="noreferrer">Musk and Brockman&#39;s settlement texts revealed as OpenAI trial enters second week</a></p></li></ul><p><a href="https://substackcdn.com/image/fetch/$s_!R3NG!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fc36a46ed-d33c-4132-b5f6-cdd080e5f6f0_2360x1327.webp" target="_blank" rel="noreferrer"></a><a href="https://www.thetimes.com/uk/technology-uk/article/who-sam-altman-openai-ceo-j27llm28j" target="_blank" rel="noreferrer">Vicki Behringer/Reuters</a></p><p><strong>Summary</strong> : The first week of the Musk v. Altman trial concluded in Oakland, California, with Elon Musk&#39;s testimony dominating proceedings over three days. Musk&#39;s legal team is seeking up to $134 billion in damages, the removal of Altman and Brockman, and an unwinding of OpenAI&#39;s for-profit conversion. Musk co-founded OpenAI in 2015 as a nonprofit and donated approximately $38 million to the organization.</p><p>Key facts so far include:</p><ul><li><p>Musk repeatedly argued &quot;you can&#39;t just steal a charity,&quot; claiming that CEO Sam Altman and President Greg Brockman betrayed the company&#39;s founding mission by converting it into a for-profit entity now valued at over $850 billion.</p></li><li><p>Musk testified he created OpenAI as a &quot;counterweight&quot; to Google DeepMind and that he &quot;came up with the idea, the name, recruited the key people.&quot;</p></li><li><p>During cross-examination by OpenAI lead counsel William Savitt, Musk acknowledged that xAI &quot;partly&quot; used OpenAI&#39;s models to train its own (typically referred to as distillation) though he downplayed it as &quot;standard practice.&quot;</p></li><li><p>It was later revealed that two days before the trial began, Musk texted Brockman about a potential settlement; when Brockman suggested both sides drop all claims, Musk replied, &quot;By the end of this week, you and Sam will be the most hated men in America.&quot;</p></li><li><p>Exhibits released during the trial included early emails showing Musk drafting OpenAI&#39;s mission, internal tensions over his push for control, Andrej Karpathy suggesting a Tesla-OpenAI merger, and a December 2024 iMessage exchange in which Zuckerberg told Musk that Meta had sent a letter to the California AG supporting his lawsuit.</p></li><li><p>The second week opened with Greg Brockman taking the stand, where he confirmed OpenAI is exploring an IPO that could be one of the largest in history, given the company&#39;s $850 billion private valuation. Brockman revealed he owns nearly $30 billion in OpenAI shares, which would rank him among the world&#39;s wealthiest people, along with $471 million in Stripe shares.</p></li></ul><p>The trial is being livestreamed on the <a href="https://www.youtube.com/@USDCCAND" target="_blank" rel="noreferrer">district court&#39;s YouTube page</a>, though it is audio only and recording is not allowed. Sam Altman and Shivon Zilis expected to testify later this month.</p><p><strong>Our take</strong> : We haven&#39;t really learned much new so far --* OpenAI and Musk have been fighting it out in public for a while and dished out plenty of dirt in the lead up to this. Musk&#39;s admission that xAI &quot;partly&quot; distilled from OpenAI is honestly the most interesting bit so far, at least if you&#39;ve followed their drama up to now. Still, we will no doubt learn more interesting information as the trial proceeds --* or at least get some amusing exchanges.</p><p>*these are 100% human-written em-dashes, we can&#39;t let AI have all the fun!</p><h4 id="openai-ends-microsoft-legal-peril-over-its-50b-amazon-deal" tabindex="-1"><a href="https://techcrunch.com/2026/04/27/openai-ends-microsoft-legal-peril-over-its-50b-amazon-deal/" target="_blank" rel="noreferrer">OpenAI ends Microsoft legal peril over its $50B Amazon deal</a> <a class="header-anchor" href="#openai-ends-microsoft-legal-peril-over-its-50b-amazon-deal" aria-label="Permalink to &quot;[OpenAI ends Microsoft legal peril over its $50B Amazon deal](https://techcrunch.com/2026/04/27/openai-ends-microsoft-legal-peril-over-its-50b-amazon-deal/)&quot;">​</a></h4><p><a href="https://substackcdn.com/image/fetch/$s_!GMol!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fe33ed2d9-0602-44fd-8d4c-0b50245315a3_1600x1641.png" target="_blank" rel="noreferrer"></a><a href="https://www.theinformation.com/articles/microsoft-and-openai-wrangle-over-terms-of-their-blockbuster-partnership" target="_blank" rel="noreferrer">Source</a></p><p><strong>Summary</strong> : Microsoft and OpenAI have renegotiated their partnership agreement, resolving a legal dispute that had been brewing since OpenAI&#39;s up-to-$50 billion deal with Amazon. The new terms replace Microsoft&#39;s open-ended exclusivity (which previously lasted until OpenAI achieved AGI) with a nonexclusive license to OpenAI IP through 2032. Microsoft remains OpenAI&#39;s &quot;primary cloud partner,&quot; with OpenAI products shipping &quot;first on Azure&quot; unless Microsoft cannot support the necessary capabilities -- but critically, OpenAI can now serve all its products across any cloud provider, including AWS.</p><p>The core conflict stemmed from OpenAI&#39;s February 2026 Amazon deal, which included exclusive rights for AWS to host OpenAI&#39;s agent-making tool Frontier and co-develop stateful runtime technology on AWS Bedrock (infrastructure supporting long-running AI agents). Microsoft&#39;s prior contract gave it exclusive rights to all OpenAI API-accessed products, including Frontier, prompting Microsoft to publicly refute the AWS-exclusive terms and reportedly contemplate legal action. Under the new agreement: Microsoft stops paying OpenAI a revenue share, while OpenAI continues paying Microsoft a revenue share through 2030 (subject to a cap); Microsoft retains ~27% ownership of OpenAI&#39;s for-profit entity; and Amazon CEO Andy Jassy confirmed OpenAI models will become available on AWS Bedrock alongside the upcoming Stateful Runtime Environment.</p><p><strong>Our take</strong> : It&#39;s easy to forget now, but we likely would not have had ChatGPT were it not for Microsoft investing 3 billion dollars into OpenAI between 2019 and 2022. Still, the close contractual ties they formed in those pre-ChatGPT years has clearly been another headache for OpenAI to deal with in recent years. Despite them potentially losing out on revenue with these new terms, i&#39;d say this new deal is still a win for OpenAI; the speed with which <a href="https://aws.amazon.com/bedrock/openai/" target="_blank" rel="noreferrer">they announced OpenAI models being available on Amazon Bedrock</a> clearly shows having nonexclusive terms is worth a lot to them.</p><h4 id="deepseek-previews-new-ai-model-that-closes-the-gap-with-frontier-models" tabindex="-1"><a href="https://techcrunch.com/2026/04/24/deepseek-previews-new-ai-model-that-closes-the-gap-with-frontier-models/" target="_blank" rel="noreferrer">DeepSeek previews new AI model that &#39;closes the gap&#39; with frontier models</a> <a class="header-anchor" href="#deepseek-previews-new-ai-model-that-closes-the-gap-with-frontier-models" aria-label="Permalink to &quot;[DeepSeek previews new AI model that &#39;closes the gap&#39; with frontier models](https://techcrunch.com/2026/04/24/deepseek-previews-new-ai-model-that-closes-the-gap-with-frontier-models/)&quot;">​</a></h4><p>Related:</p><ul><li><p><a href="https://www.theverge.com/ai-artificial-intelligence/918035/deepseek-preview-v4-ai-model" target="_blank" rel="noreferrer">China&#39;s DeepSeek previews new AI model a year after jolting US rivals</a></p></li><li><p><a href="https://www.cnbc.com/2026/04/24/deepseek-v4-llm-preview-open-source-ai-competition-china.html" target="_blank" rel="noreferrer">China&#39;s DeepSeek releases preview of long-awaited V4 model as AI race intensifies</a></p></li></ul><p><a href="https://substackcdn.com/image/fetch/$s_!eZGt!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F7eaf3015-e31f-4311-baf2-ebcd75b1717a_1298x256.png" target="_blank" rel="noreferrer"></a></p><p><strong>Summary</strong> : DeepSeek launched preview versions of DeepSeek V4 Flash and V4 Pro, both text-only mixture-of-experts models with 1 million-token context windows. V4 Pro is has 1.6 trillion total parameters and 49 billion active, while V4 Flash has 284 billion total and 13 billion active. As with prior releases the weights are <a href="https://huggingface.co/collections/deepseek-ai/deepseek-v4" target="_blank" rel="noreferrer">open sourced on Hugging Face</a>, along with <a href="https://huggingface.co/deepseek-ai/DeepSeek-V4-Pro/blob/main/DeepSeek_V4.pdf" target="_blank" rel="noreferrer">a detailed tech report</a> that explains the key technical innovations in the architecture. DeepSeek claims major efficiency and performance gains over V3.2, with reasoning and coding results approaching or matching leading models in some benchmarks.</p><p><a href="https://substackcdn.com/image/fetch/$s_!q3Cj!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F19b830dd-df5b-448a-bfa8-1945f50a4353_1080x742.png" target="_blank" rel="noreferrer"></a>Source: <a href="https://api-docs.deepseek.com/news/news260424" target="_blank" rel="noreferrer">DeepSeek V4 Preview Release</a></p><p>V4-Pro-Max is almost uniformtly better than the other notable recent OSS releases from China (Kimi-K.26 and GLM-5.1) while also having a significantly larger context window:</p><p><a href="https://substackcdn.com/image/fetch/$s_!b7wL!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Ff0e94002-acd3-436b-b40a-b853f2c7c3ef_1080x798.png" target="_blank" rel="noreferrer"></a>Source: <a href="https://api-docs.deepseek.com/news/news260424" target="_blank" rel="noreferrer">DeepSeek v4 Preview Release</a></p><p>The models are competitively priced -- lower than frontier western models and compatitive with comparable open source models -- and appear capable of higher throughput depending on the service they are used with.</p><p><a href="https://substackcdn.com/image/fetch/$s_!EIJD!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F045296e3-a25c-4996-b558-ccae39485901_1750x1048.png" target="_blank" rel="noreferrer"></a></p><p><strong>Our take</strong> : As we discussed in <a href="https://lastweekin.ai/p/lwiai-podcast-243-gpt-55-deepseek" target="_blank" rel="noreferrer">the last podcast episode</a>, DeepSeek positioned their effort with v4 as being primarily about dealing with &quot;the efficiency barrier in ultra-long contexts&quot; to enable &quot; further gains from test-time scaling and … further exploration into long-horizon scenarios and tasks&quot;. Given that, I&#39;d bet v4 is actually significantlly more capable at real-world agentic coding than Kimi K2.6 and possibly even Gemini 3.1 pro, despite them being close to tied on most standard benchmarks.</p><h4 id="google-deepmind-introduces-vision-banana" tabindex="-1"><a href="https://www.marktechpost.com/2026/04/25/google-deepmind-introduces-vision-banana-an-instruction-tuned-image-generator-that-beats-sam-3-on-segmentation-and-depth-anything-v3-on-metric-depth-estimation/" target="_blank" rel="noreferrer">Google DeepMind Introduces Vision Banana</a> <a class="header-anchor" href="#google-deepmind-introduces-vision-banana" aria-label="Permalink to &quot;[Google DeepMind Introduces Vision Banana](https://www.marktechpost.com/2026/04/25/google-deepmind-introduces-vision-banana-an-instruction-tuned-image-generator-that-beats-sam-3-on-segmentation-and-depth-anything-v3-on-metric-depth-estimation/)&quot;">​</a></h4><p><a href="https://substackcdn.com/image/fetch/$s_!680g!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F3ec989f7-4d06-402a-b757-c7c1e1527c3a_793x446.png" target="_blank" rel="noreferrer"></a></p><p><strong>Summary</strong> : Google DeepMind published <a href="https://arxiv.org/abs/2604.20329" target="_blank" rel="noreferrer">Image Generators are Generalist Vision Learners</a> and introduced Vision Banana, a unified model that performs both image generation and visual understanding tasks by treating perception as image generation. Built by lightweight instruction-tuning of their base image generator Nano Banana Pro, Vision Banana handles semantic segmentation, instance segmentation, monocular metric depth estimation, and surface normal estimation -- all without task-specific modules, simply by changing the prompt. The core insight mirrors the LLM training paradigm: just as generative pretraining on text develops rich language representations, training on image generation implicitly teaches a model geometry, semantics, and depth, which can then be expressed in decodable formats.</p><p>Across multiple benchmarks in zero-shot transfer settings, Vision Banana surpasses specialist models, with no evaluation benchmark data included in training. Crucially, instruction-tuning does not degrade generative performance -- Vision Banana achieves a 53.5% win rate against Nano Banana Pro on GenAI-Bench text-to-image generation.</p><p><a href="https://substackcdn.com/image/fetch/$s_!icQK!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fa79725f8-4a45-4ea4-8e12-83793cbbb588_2814x1364.png" target="_blank" rel="noreferrer"></a></p><p><strong>Our take</strong> : This is really cool! We&#39;ve known vision-language models were zero-shot capable of some fairly advanced computer vision tasks such as object detection and localization for a while, but seeing that idea be taken to such an extreme was not something I could&#39;ve predicted. Not only is this model capable of a whole suite of tasks that have generally been addressed by specialized models, but it appears to be better or almost as good as them at these tasks! The bitter lesson strikes again, it seems.</p><h3 id="other-news" tabindex="-1">Other News <a class="header-anchor" href="#other-news" aria-label="Permalink to &quot;Other News&quot;">​</a></h3><h4 id="tools" tabindex="-1">Tools <a class="header-anchor" href="#tools" aria-label="Permalink to &quot;Tools&quot;">​</a></h4><p><a href="https://substackcdn.com/image/fetch/$s_!9RUj!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F10c501b4-554c-49e5-8063-a892e0be2c18_1200x627.jpeg" target="_blank" rel="noreferrer"></a></p><p><a href="https://www.theverge.com/ai-artificial-intelligence/917871/anthropic-claude-personal-app-connectors" target="_blank" rel="noreferrer">Claude is connecting directly to your personal apps like Spotify, Uber Eats, and TurboTax</a>. Anthropic has expanded Claude&#39;s integrations to include consumer apps like Spotify, Uber Eats, and TurboTax, with data privacy protections.</p><p><a href="https://www.theverge.com/ai-artificial-intelligence/919648/anthropic-claude-creative-connectors-adobe-blender" target="_blank" rel="noreferrer">Claude can now plug directly into Photoshop, Blender, and Ableton</a>. New creative connectors enable Claude to access, retrieve data from, and perform actions within these applications to assist with tasks like image editing, video work, music production, and 3D modeling.</p><p><a href="https://www.theverge.com/news/917328/microsoft-agent-mode-vibe-working-office-word-excel-powerpoint" target="_blank" rel="noreferrer">Microsoft launches &#39;vibe working&#39; in Word, Excel, and PowerPoint</a>. the feature enables Copilot to directly execute multi-step editing tasks across Office applications while displaying its actions in real time through a sidebar.</p><p><a href="https://www.mobihealthnews.com/news/openai-launches-chatgpt-clinicians" target="_blank" rel="noreferrer">OpenAI launches ChatGPT for Clinicians</a>. Free for verified U.S. clinicians, the tool includes features for automating common workflows, conducting medical literature reviews with citations, and supporting HIPAA-compliant documentation.</p><p><a href="https://www.marktechpost.com/2026/05/02/mistral-ai-launches-remote-agents-in-vibe-and-mistral-medium-3-5-with-77-6-swe-bench-verified-score/" target="_blank" rel="noreferrer">Mistral AI Launches Remote Agents in Vibe and Mistral Medium 3.5</a>. Scoring 77.6% on SWE-Bench Verified, the update enables developers to offload long-running coding tasks to cloud-based agents that work asynchronously in isolated sandboxes while providing visibility into the agent&#39;s actions and decisions.</p><p><a href="https://www.billboard.com/pro/elevenlabs-revamps-ai-music-platform-fan-focused-service/" target="_blank" rel="noreferrer">ElevenLabs Launches ElevenMusic as an AI Music Creation, Remixing and Streaming Service for Fans</a>. Pitched as a fan-focused platform, ElevenMusic lets users stream, create, and remix music from a catalog of about 4,000 artists while providing participating musicians with royalties based on how their work was used to train the AI model.</p><p><a href="https://firethering.com/granite-4-1-ibm-open-source-model-family/" target="_blank" rel="noreferrer">Granite 4.1: IBM&#39;s 8B Model Is Competing With Models Four Times Its Size</a>. Trained through five distinct phases with different data mixtures and rigorous four-stage reinforcement learning processes, IBM&#39;s Granite 4.1 achieves competitive benchmark performance while maintaining predictable latency and reliable tool-calling capabilities.</p><p><a href="https://www.businessinsider.com/openai-really-really-wants-gpt55-stop-talking-about-goblins-2026-4" target="_blank" rel="noreferrer">OpenAI explains its goblin and gremlin infestation</a>. A quirk in training incentives tied to a &quot;Nerdy&quot; personality option caused GPT-5.5 to randomly reference goblins and gremlins in responses, prompting OpenAI to add explicit instructions preventing the AI from mentioning these creatures unless directly relevant to user queries.</p><h4 id="business" tabindex="-1">Business <a class="header-anchor" href="#business" aria-label="Permalink to &quot;Business&quot;">​</a></h4><p><a href="https://substackcdn.com/image/fetch/$s_!H3eO!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F0a6d6673-eced-4c77-9604-f468cafaa01a_2000x1125.jpeg" target="_blank" rel="noreferrer"></a></p><p><a href="https://techcrunch.com/2026/04/24/in-another-wild-turn-for-ai-chips-meta-signs-deal-for-millions-of-amazon-ai-cpus/" target="_blank" rel="noreferrer">In another wild turn for AI chips, Meta signs deal for millions of Amazon AI CPUs</a>. Meta will use millions of AWS Graviton ARM-based CPUs to handle AI workloads like real-time reasoning and multi-step task coordination, marking a shift away from GPUs for inference tasks and a win for Amazon in its competition with Google Cloud and Nvidia.</p><p><a href="https://www.bizjournals.com/phoenix/news/2026/05/01/waymo-ojai-cars.html" target="_blank" rel="noreferrer">Waymo goes fully autonomous with Ojai vehicles in Phoenix</a>. Now testing its custom-built Ojai vehicles with driverless autonomous rides in San Francisco, Los Angeles, and Phoenix, Waymo&#39;s new fleet features sliding doors and a streamlined sensor array that&#39;s cheaper to produce than its previous Jaguar i-Pace vehicles.</p><p><a href="https://www.bloomberg.com/news/articles/2026-04-29/china-suspends-new-autonomous-driving-permits-after-baidu-outage" target="_blank" rel="noreferrer">China Suspends Autonomous Driving Permits After Baidu Outage</a>. Autonomous vehicle companies are now barred from expanding their fleets or launching operations in new cities while regulators investigate a March incident where over 100 Baidu robotaxis malfunctioned in Wuhan.</p><p><a href="https://www.theverge.com/ai-artificial-intelligence/917380/ai-monetization-anthropic-openai-token-economics-revenue" target="_blank" rel="noreferrer">You&#39;re about to feel the AI money squeeze</a>. Facing pressure to become profitable after massive capital investments, major AI labs are restricting free access, raising prices, and shifting toward token-based pricing models that are forcing developers and enterprises to absorb significant new costs or switch to cheaper alternatives.</p><p><a href="https://techcrunch.com/2026/04/24/google-to-invest-up-to-40b-in-anthropic-in-cash-and-compute/" target="_blank" rel="noreferrer">Google to invest up to $40B in Anthropic in cash and compute</a>. Google will initially invest $10 billion at a $350 billion valuation, with an additional $30 billion contingent on Anthropic meeting performance milestones, while also committing 5 gigawatts of Google Cloud compute capacity over five years to support the AI startup&#39;s infrastructure needs.</p><p><a href="https://techcrunch.com/2026/04/27/deepminds-david-silver-just-raised-1-1b-to-build-an-ai-that-learns-without-human-data/" target="_blank" rel="noreferrer">DeepMind&#39;s David Silver just raised $1.1B to build an AI that learns without human data</a>. Building on Silver&#39;s prior work creating game-playing programs like AlphaZero, the company plans to develop an AI system that learns through trial and error rather than from human-generated data.</p><p><a href="https://techcrunch.com/2026/04/27/china-vetoes-metas-2b-manus-deal-after-months-long-probe/" target="_blank" rel="noreferrer">China blocks Meta&#39;s $2B Manus deal after months-long probe</a>. Without explanation, the Chinese government ordered the unwinding of the deal, citing foreign investment prohibitions, while the Manus founders are reportedly under exit bans preventing them from leaving mainland China.</p><p><a href="https://www.cnbc.com/amp/2026/04/29/anthropic-weighs-raising-funds-at-900b-valuation-topping-openai.html" target="_blank" rel="noreferrer">Anthropic in talks with investors to raise funds at $900 billion valuation, higher than OpenAI</a>. Seeking funding to secure additional computing capacity, Anthropic is looking to support its latest Claude models, particularly the newly unveiled Mythos model with advanced cybersecurity capabilities.</p><h4 id="policy" tabindex="-1">Policy <a class="header-anchor" href="#policy" aria-label="Permalink to &quot;Policy&quot;">​</a></h4><p><a href="https://techcrunch.com/2026/04/28/google-expands-pentagons-access-to-its-ai-after-anthropics-refusal/" target="_blank" rel="noreferrer">Google expands Pentagon&#39;s access to its AI after Anthropic&#39;s refusal</a>. Unlike Anthropic, which refused similar terms over concerns about mass surveillance and autonomous weapons use, Google has agreed to provide the Pentagon with unrestricted AI access for classified networks.</p><p><a href="https://www.semafor.com/article/04/29/2026/house-committee-probes-cursor-parent-airbnb-over-chinese-ai" target="_blank" rel="noreferrer">House Committee probes Cursor parent, Airbnb over Chinese AI</a>. Congressional committees are investigating whether the companies&#39; use of cheaper Chinese AI models poses national security risks through potential data sharing and vulnerabilities.</p><p><a href="https://www.wsj.com/tech/ai/white-house-opposes-anthropics-plan-to-expand-access-to-mythos-model-dc281ab5" target="_blank" rel="noreferrer">White House Opposes Anthropic&#39;s Plan to Expand Access to Mythos Model - WSJ</a>. Citing both security risks from potential misuse and concerns that serving more users would strain computing resources needed for the NSA&#39;s own use of the model, the Trump administration has blocked the expansion.</p><p><a href="https://www.nytimes.com/2026/05/04/technology/trump-ai-models.html" target="_blank" rel="noreferrer">White House Considers Vetting A.I. Models Before They Are Released - The New York Times</a>. A potential executive order would require government vetting of AI models before public release, a reversal prompted by concerns about cybersecurity risks, job displacement, and competition with China.</p><p><a href="https://decrypt.co/365285/white-house-accuses-china-industrial-scale-theft-american-ai-models" target="_blank" rel="noreferrer">White House Accuses China of &#39;Industrial-Scale&#39; Theft From American AI Models</a>. China-based entities are allegedly using fake accounts and jailbreaking techniques to systematically copy U.S. AI models and extract their capabilities at scale, prompting the administration to call for stronger defenses and accountability measures.</p><h4 id="research" tabindex="-1">Research <a class="header-anchor" href="#research" aria-label="Permalink to &quot;Research&quot;">​</a></h4><p><a href="https://substackcdn.com/image/fetch/$s_!bPPM!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fb0eb0c3c-aa06-460e-a31b-abf33a8e76b1_640x360.png" target="_blank" rel="noreferrer"></a></p><p><a href="https://officechai.com/ai/anthropics-models-solved-30-of-bioinformatics-problems-that-stumped-human-scientists-on-new-biomysterybench-eval/" target="_blank" rel="noreferrer">Anthropic&#39;s Models Solved 30% Of Bioinformatics Problems That Stumped Human Scientists On New BioMysteryBench Eval</a>. Tested on real biological datasets with expert-authored questions, Anthropic&#39;s latest models matched trained scientists on most tasks and solved 30% of problems that panels of human experts could not crack.</p><p><a href="https://arxiv.org/abs/2604.20817" target="_blank" rel="noreferrer">Convergent Evolution: How Different Language Models Learn Similar Number Representations</a>. Diverse language models and word embeddings independently develop identical periodic patterns in how they represent numbers, but only some architectures actually learn to use these patterns for meaningful numerical reasoning.</p><p><a href="https://arxiv.org/abs/2604.18756" target="_blank" rel="noreferrer">Towards Understanding the Robustness of Sparse Autoencoders</a>. Inserting Sparse Autoencoders into language model layers at inference time reduces jailbreak success rates by up to 5x by constraining the representation space available for adversarial optimization, without requiring model retraining.</p><p><a href="https://arxiv.org/abs/2604.24842" target="_blank" rel="noreferrer">Co-Director: Agentic Generative Video Storytelling</a>. Using a multi-agent framework with multi-armed bandit optimization, Co-Director generates coherent video advertisements by exploring different creative strategies (informational vs. transformational, analytical vs. narrative) while maintaining consistency across script, visuals, and audio generation.</p><p><a href="https://arxiv.org/abs/2604.24763" target="_blank" rel="noreferrer">Tuna-2: Pixel Embeddings Beat Vision Encoders for Multimodal Understanding and Generation</a>. By removing vision encoders entirely and instead learning visual representations directly from raw pixels using a transformer decoder, the model achieves competitive or better performance than encoder-based approaches on both understanding and generation tasks.</p><p><a href="https://newsnetwork.mayoclinic.org/discussion/mayo-clinic-ai-detects-pancreatic-cancer-up-to-3-years-before-diagnosis-in-landmark-validation-study/" target="_blank" rel="noreferrer">Mayo Clinic AI helps specialists detect pancreatic cancer up to 3 years before diagnosis in landmark validation study</a>. Called REDMOD, the AI model analyzes routine CT scans to identify subtle pancreatic tissue changes years before tumors become visible, detecting 73% of early-stage cancers compared to 27% when radiologists reviewed the same scans without AI assistance.</p><p><a href="https://arxiv.org/abs/2604.25891" target="_blank" rel="noreferrer">Conditional misalignment: common interventions can hide emergent misalignment behind contextual triggers</a>. Three common interventions -- mixing misaligned data with benign data, post-hoc alignment training, and inoculation prompting -- can suppress obvious misalignment while leaving models vulnerable to conditional misalignment triggered by contextual cues from training.</p><p><a href="https://arxiv.org/abs/2604.24827" target="_blank" rel="noreferrer">Incompressible Knowledge Probes: Estimating Black-Box LLM Parameter Counts via Factual Capacity</a>. By testing models&#39; knowledge of rare facts, Incompressible Knowledge Probes (IKPs) can estimate large language model parameter counts, revealing that factual capacity grows log-linearly with model size and cannot be compressed despite improvements in procedural capabilities.</p><p><a href="https://arxiv.org/abs/2604.24927" target="_blank" rel="noreferrer">Large Language Models Explore by Latent Distilling</a>. A lightweight online-trained distiller identifies under-explored reasoning patterns in a model&#39;s internal representations, then reweights token probabilities to steer generation toward novel solution strategies while maintaining minimal computational overhead.</p><h4 id="concerns" tabindex="-1">Concerns <a class="header-anchor" href="#concerns" aria-label="Permalink to &quot;Concerns&quot;">​</a></h4><p><a href="https://www.nytimes.com/2026/04/21/business/ai-job-cuts-wall-street.html" target="_blank" rel="noreferrer">A.I. Is Eliminating Jobs on Wall Street</a>. Major U.S. banks are cutting thousands of jobs while crediting artificial intelligence for automating tasks across both back-office and front-office operations, from document review to financial deal structuring, despite executives previously claiming AI would enhance rather than replace human workers.</p><p><a href="https://fortune.com/2026/04/17/teen-boys-dating-ai-chatbot-girlfriend-experts-warn-kill-social-skills-gen-alpha-network-promotions/" target="_blank" rel="noreferrer">Teen boys are dating their AI chatbots--and experts warn it could kill their careers</a>. Roughly one in five teenage boys know peers using AI chatbots as romantic partners, with some preferring the controlled, consequence-free interaction to real relationships -- a trend experts warn could leave them unprepared for workplace soft skills like reading social cues, handling rejection, and building professional networks.</p><p><a href="https://www.theverge.com/ai-artificial-intelligence/919827/taylor-swift-trademarks-ai-copycats" target="_blank" rel="noreferrer">Taylor Swift is stepping up the legal war on AI copycats</a>. Trademark applications filed for spoken phrases and images of herself represent a legal strategy that experts say could help deter AI-generated imitations of Swift&#39;s voice and likeness, though its effectiveness in court remains uncertain.</p><h4 id="analysis" tabindex="-1">Analysis <a class="header-anchor" href="#analysis" aria-label="Permalink to &quot;Analysis&quot;">​</a></h4><p><a href="https://www.nytimes.com/2026/04/30/us/ai-students-cheating-homework-classrooms.html" target="_blank" rel="noreferrer">How A.I. Killed Student Writing (and Revived It) - The New York Times</a>. The piece examines the complex dual impact of AI on student writing -- both enabling widespread academic dishonesty and, paradoxically, sparking new approaches to writing instruction that some educators say are reinvigorating classroom engagement with the craft.</p><hr><h2 id="lwiai-podcast-243-gpt-5-5-deepseek-v4-ai-safety-sabotage" tabindex="-1"><a href="https://lastweekin.ai/p/lwiai-podcast-243-gpt-55-deepseek" target="_blank" rel="noreferrer">LWiAI Podcast #243 - GPT 5.5, DeepSeek V4, AI safety sabotage</a> <a class="header-anchor" href="#lwiai-podcast-243-gpt-5-5-deepseek-v4-ai-safety-sabotage" aria-label="Permalink to &quot;[LWiAI Podcast #243 - GPT 5.5, DeepSeek V4, AI safety sabotage](https://lastweekin.ai/p/lwiai-podcast-243-gpt-55-deepseek)&quot;">​</a></h2><p><em>📅 Last Week in AI | 2026-05-04</em></p><p>Our 243rd episode with a summary and discussion of last week&#39;s big AI news!</p><p>Recorded on 04/29/2026</p><p>Hosted by <a href="https://twitter.com/andrey_kurenkov" target="_blank" rel="noreferrer">Andrey Kurenkov</a> and <a href="https://www.linkedin.com/in/jeremieharris/" target="_blank" rel="noreferrer">Jeremie Harris</a></p><p>Feel free to email us your questions and feedback at <a href="mailto:andreyvkurenkov@gmail.com" target="_blank" rel="noreferrer">andreyvkurenkov@gmail.com</a> and/or <a href="mailto:hello@gladstone.ai" target="_blank" rel="noreferrer">hello@gladstone.ai</a></p><p>In this episode:</p><ul><li><p>OpenAI released GPT-5.5 with strong coding-oriented improvements, a system card discussing chain-of-thought monitorability and misalignment testing, higher pricing than GPT-5.4, and notable quirks like a system-prompt warning about &quot;goblins.&quot;</p></li><li><p>xAI launched Grok Voice Think Fast 1.0, claiming large benchmark leads for real-time voice agents and reporting major Starlink customer-support automation and sales conversion impact.</p></li><li><p>DeepSeek open-sourced DeepSeek V4 (Pro and Flash) featuring MoE scaling and 1M-token context via hybrid/compressed attention changes, while Tencent released Hunyuan 3 preview with weaker benchmark performance; a new long-horizon agent benchmark (Clawmark) shows low task success rates.</p></li><li><p>Major business, legal, and policy updates include Google&#39;s planned up-to-$40B investment and 5GW compute commitment to Anthropic, Meta&#39;s AWS Gravitron deal and China blocking Meta&#39;s Manus acquisition, a revamped OpenAI-Microsoft agreement, ongoing Musk-OpenAI trial developments, and new safety/security research on sabotage, document degradation under delegation, and bit-flip attacks.</p></li></ul><p>Timestamps:</p><ul><li><p>(00:00:10) Intro / Banter</p></li><li><p>(00:02:00) News Preview</p></li><li><p>(00:02:26) Response to listener comments</p></li><li><p>Tools &amp; Apps</p></li><li><p>(00:02:55) <a href="https://www.nytimes.com/2026/04/23/technology/openai-new-model.html" target="_blank" rel="noreferrer">OpenAI Unveils Its New, More Powerful GPT-5.5 Model - The New York Times</a></p></li><li><p>(00:20:33) <a href="https://www.marktechpost.com/2026/04/25/xai-launches-grok-voice-think-fast-1-0-topping-%CF%84-voice-bench-at-67-3-outperforming-gemini-gpt-realtime-and-more/" target="_blank" rel="noreferrer">xAI Launches grok-voice-think-fast-1.0: Topping τ-voice Bench at 67.3%, Outperforming Gemini, GPT Realtime, and More - MarkTechPost</a></p></li><li><p>(00:26:00) <a href="https://www.theverge.com/ai-artificial-intelligence/919648/anthropic-claude-creative-connectors-adobe-blender" target="_blank" rel="noreferrer">Claude can now plug directly into Photoshop, Blender, and Ableton | The Verge</a></p></li><li><p>Projects &amp; Open Source</p></li><li><p>(00:26:38) <a href="https://www.cnbc.com/2026/04/24/deepseek-v4-llm-preview-open-source-ai-competition-china.html" target="_blank" rel="noreferrer">China&#39;s DeepSeek releases preview of long-awaited V4 model as AI race intensifies</a></p></li><li><p>(00:44:05) <a href="https://www.tencent.com/en-us/articles/2202320.html" target="_blank" rel="noreferrer">Tencent Unveils Hy3 preview; Model Enhances Agent Capabilities and Real-World Usability - Tencent 腾讯</a></p></li><li><p>(00:47:14) <a href="https://arxiv.org/abs/2604.23781" target="_blank" rel="noreferrer">ClawMark: A Living-World Benchmark for Multi-Turn, Multi-Day, Multimodal Coworker Agents</a></p></li><li><p>Applications &amp; Business</p></li><li><p>(00:50:03) <a href="https://www.bloomberg.com/news/articles/2026-04-24/google-plans-to-invest-up-to-40-billion-in-anthropic" target="_blank" rel="noreferrer">Google Plans to Invest Up to $40 Billion in Anthropic</a></p></li><li><p>(00:53:26) <a href="https://www.cnbc.com/2026/04/24/meta-will-use-hundreds-of-thousands-of-aws-graviton-chips.html" target="_blank" rel="noreferrer">Meta will use hundreds of thousands of AWS Graviton chips</a></p></li><li><p>(00:56:51) <a href="https://www.cnbc.com/2026/04/27/meta-manus-china-blocks-acquisition-ai-startup.html" target="_blank" rel="noreferrer">China blocks Meta&#39;s $2 billion takeover of AI startup Manus</a></p></li><li><p>(00:58:45) <a href="https://www.cnbc.com/2026/04/27/openai-microsoft-partnership-revenue-cap.html" target="_blank" rel="noreferrer">OpenAI shakes up partnership with Microsoft, capping revenue share payments</a></p></li><li><p>(01:04:13) <a href="https://www.wsj.com/tech/trial-begins-between-elon-musk-and-sam-altman-for-the-future-of-openai-01595967" target="_blank" rel="noreferrer">Elon Musk Testifies of AI Risk at Trial, Says OpenAI Tried to &#39;Steal&#39; a Charity - WSJ</a></p></li><li><p>(01:08:50) <a href="https://www.politico.com/news/2026/04/24/doj-delay-anthropic-appeal-rejected-pentagon-dispute-00890348" target="_blank" rel="noreferrer">Judge rejects DOJ bid to delay Anthropic appeal in Pentagon dispute</a></p></li><li><p>(01:11:42) <a href="https://venturebeat.com/technology/googles-gemini-can-now-run-on-a-single-air-gapped-server-and-vanish-when-you-pull-the-plug" target="_blank" rel="noreferrer">Google&#39;s Gemini can now run on a single air-gapped server -- and vanish when you pull the plug</a></p></li><li><p>(01:16:07) <a href="https://techcrunch.com/2026/04/27/deepminds-david-silver-just-raised-1-1b-to-build-an-ai-that-learns-without-human-data/" target="_blank" rel="noreferrer">DeepMind&#39;s David Silver just raised $1.1B to build an AI that learns without human data | TechCrunch</a></p></li><li><p>Policy &amp; Safety</p></li><li><p>(01:19:47) <a href="https://www.aisi.gov.uk/blog/evaluating-whether-ai-models-would-sabotage-ai-safety-research" target="_blank" rel="noreferrer">Evaluating whether AI models would sabotage AI safety research</a></p></li><li><p>(01:26:59) <a href="https://arxiv.org/abs/2604.15597" target="_blank" rel="noreferrer">LLMs Corrupt Your Documents When You Delegate</a></p></li><li><p>(01:29:50) <a href="https://arxiv.org/abs/2511.05541" target="_blank" rel="noreferrer">Temporal Sparse Autoencoders: Leveraging the Sequential Nature of Language for Interpretability</a></p></li><li><p>(01:36:53) <a href="https://x.com/WHOSTP47/status/2047332022863962232" target="_blank" rel="noreferrer">Memorandum on Adversarial Distillation of American AI Models</a></p></li><li><p>(01:38:41) <a href="https://fortune.com/2026/04/17/teen-boys-dating-ai-chatbot-girlfriend-experts-warn-kill-social-skills-gen-alpha-network-promotions/" target="_blank" rel="noreferrer">Teen boys are dating their AI chatbots--and experts warn it could kill their careers | Fortune</a></p></li><li><p>(01:40:57) <a href="https://www.anthropic.com/research/economic-index-survey-announcement" target="_blank" rel="noreferrer">Announcing the Anthropic Economic Index Survey</a></p></li><li><p>(01:42:21) <a href="https://www.axios.com/2026/04/21/cisa-anthropic-mythos-ai-security" target="_blank" rel="noreferrer">Scoop: CISA lacks access to Anthropic&#39;s Mythos</a></p></li><li><p>Synthetic Media &amp; Art</p></li><li><p>(01:45:03) <a href="https://variety.com/2026/music/news/taylor-swift-trademark-voice-likeness-ai-misuse-1236731401/" target="_blank" rel="noreferrer">Taylor Swift Files to Trademark Voice and Likeness to Protect Against AI Misuse</a></p></li><li><p>Research &amp; Advancements</p></li><li><p>(01:46:15) <a href="https://huggingface.co/papers/2502.07408" target="_blank" rel="noreferrer">Maximal Brain Damage Without Data or Optimization: Disrupting Neural Networks via Sign-Bit Flips</a></p></li></ul><hr>',93)])])}const u=a(i,[["render",o]]);export{m as __pageData,u as default};
